{
  "name": "CHOICES",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare-eligible individuals, families, and caregivers of all ages and income levels.[2][9]",
    "asset_limits": "No asset limits or tests apply to CHOICES counseling services.[2][6]",
    "other_requirements": ["Medicare-eligible: US citizens or permanent residents aged 65+; certain younger people with disabilities approved by Social Security Administration (e.g., collecting SSDI for 24 months or 40 quarters of work).[4][9]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased, one-on-one counseling on Medicare (Parts A, B, C, D), Medicare Supplement, prescription drug coverage; enrollment assistance and plan comparisons; eligibility screening and application help for cost-assistance programs like Medicaid, Medicare Savings Program (MSP), Low-Income Subsidy (Extra Help/LIS); information on rights, fraud detection, and related insurance.[2][5][7][9]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-994-9422 (statewide CHOICES line to speak with a counselor).[5][9]", "Website: https://portal.ct.gov/ADS-CHOICES (official program page).[5][9]", "Local Area Agencies on Aging (AAA): Contact one of 5 AAAs for in-person or phone counseling (e.g., 203-757-5449 for Western CT).[10]", "Benefits Check Up tool: Confidential online screening via local counselors or websites.[3]"],
    "processing_time": "Immediate counseling available by phone or appointment; no formal processing for services.[9]",
    "waitlist": null,
    "forms": ["No specific forms for CHOICES counseling; forms may be provided for assisted applications to MSP, LIS, or Medicaid.[6]"],
    "documents": ["For counseling: None required. For assisted benefit applications: Proof of income, Medicare info, residency (varies by program like MSP or LIS).[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide via 5 Area Agencies on Aging (AAA).",
    "regional_variations": "Delivered through 5 regional AAAs with local counselors and offices; services consistent but access points vary by AAA region (e.g., North Central AAA, Western CT AAA).[2][7][10]",
    "offices_or_providers": ["Administered by Department of Aging and Disability Services (ADS) via 5 AAAs and Center for Medicare Advocacy.[2][5][10]"]
  },
  "official_source": "https://portal.ct.gov/ADS-CHOICES",
  "gotchas": ["Not a direct benefits program—provides counseling and application assistance only, not financial aid or healthcare itself.[9]", "Counselors are certified volunteers or staff, not insurance agents, and do not sell plans.[1][4]", "For cost-assistance like MSP/LIS, apply through CHOICES but note MSP has higher income limits ($85,000/year possible for full Medicaid) and no asset test in CT—prefer MSP over direct LIS.[6]", "Open enrollment for Medicare plans: Oct 15-Dec 7.[8]"],
  "data_shape_notes": "No income/asset tests for core counseling; services uniform statewide but delivered regionally via 5 AAAs; focuses on Medicare navigation and eligibility screening for related aid programs like MSP (no assets, high income threshold)."
}

{
  "name": "Connecticut Statewide Respite Care Program (CSRCP)",
  "eligibility": {
    "age": null,
    "income_limits": "Varies by source and date (updated annually); examples: ≤$55,561/year (2023)[1], ≤$57,339/year (recent)[6], ≤$58,772/year (recent)[3]. Income includes Social Security (minus Medicare Part B), SSI, Railroad Retirement, veterans' benefits, and other payments. No household size variation specified; applies to individual with dementia.",
    "asset_limits": "Liquid assets ≤$147,715 (2023)[1], ≤$152,442 (recent)[6], ≤$156,253 (recent)[3]. Liquid assets typically include cash, bank accounts, stocks; exemptions not detailed but primary residence, one vehicle often exempt in similar programs.",
    "other_requirements": [
      "Diagnosis of Alzheimer's or related irreversible/deteriorating dementia (e.g., multi-infarct, Parkinson's, Lewy Body, Huntington's, Normal Pressure Hydrocephalus, Pick's); requires Physician Statement certifying medical exam ruling out reversible causes like depression or drug interactions[2][3][6]",
      "Not enrolled in Connecticut Homecare Program for Elders[1][3]",
      "Caregiver stress/need prioritized (e.g., primary caregiver with impairments, combative/non-compliant individual)[2]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Subsidizes respite services up to $7,500/year (contingent on funding and care manager-assessed need)[1][3][8]; specific services: adult day care, home health aide, personal care assistant, homemaker, companion, nursing care, personal emergency response system, short-term nursing home/assisted living (max 30 days out-of-home respite excluding adult day care)[1][3][4]; also care planning, info/support; 20% co-pay required (waivable for hardship)[3][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact local Area Agency on Aging (AAA) or sponsor agency serving your town (statewide via 6 AAAs)[1][2][3]",
      "Phone examples: Senior Resources (Eastern CT) 860-887-3561[3], WCAAA (Western CT) 203-757-5449 or 800-994-9422[6]",
      "Application submitted to sponsor agency; self-directed option available[3][6]"
    ],
    "processing_time": "Sponsor agency performs assessment and makes written eligibility determination (timeline not specified; contact local AAA)[2]",
    "waitlist": "Funding contingent on availability; potential wait due to limited funds (not explicitly stated)[1][3]",
    "forms": [
      "Physician Statement (included in application)[3][6]"
    ],
    "documents": [
      "Proof of income/assets",
      "Physician Statement for dementia diagnosis",
      "Authorization docs if conservator/POA[3]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered by 6 regional Area Agencies on Aging (AAAs) with varying income/asset thresholds reported, providers, and contact offices; wait times/funding may vary by region due to demand[1][3][6]",
    "offices_or_providers": [
      "Area Agencies on Aging (e.g., Senior Resources, WCAAA); Alzheimer's Association CT Chapter; partnership with CT Dept of Aging & Disability Services[1][8]"
    ]
  },
  "official_source": "https://portal.ct.gov/ads/knowledge-base/articles/independent-living-services/healthy-living-services/connecticut-statewide-respite-care[8]; Regulations: https://eregulations.ct.gov/eRegsPortal/Browse/getDocument?guid=%7B30A0E155-0200-C294-AF6B-15887B1A99E2%7D[2]",
  "gotchas": [
    "Income/asset limits update annually (e.g., 2023: $55,561/$147,715; check current with local AAA)[1][3][6]",
    "Mandatory 20% co-pay (waivable only for hardship)[3][6]",
    "Funding limited—not guaranteed; prioritized by need/caregiver stress[1][2]",
    "Cannot combine with CT Homecare for Elders[1][3]",
    "Physician must certify irreversible dementia (not generic)[2]",
    "Providers cannot be spouse/conservator (relatives possible with approval)[4]"
  ],
  "data_shape_notes": "Administered regionally via AAAs with annually adjusted income/asset limits (no household size table); funding capped at $7,500/year with priority tiers; self-directed care option; co-pay required"
}

{
  "name": "Connecticut State Supplement for the Aged, Blind, and Disabled (AABD)",
  "eligibility": {
    "age": 65,
    "income_limits": "Gross income must not exceed three times the current maximum SSI amount per eligible person (exact dollar amount varies; compared to monthly needs standard). Net income must be below the state-established standard of living. Must have another source of income (e.g., SSI, SSDI, Social Security, Veterans benefits) that is supplemental—either receiving SSI or income exceeds SSI standard but below state need standard[2][6][7][8].",
    "asset_limits": "Assets cannot exceed $1,600 for an individual or $2,400 for a couple. Counts liquid assets; if owning a home, a lien is placed on the home. Exemptions not fully detailed in sources[6].",
    "other_requirements": ["Aged (65+), blind, or disabled (meets SSI functional criteria for age 65+, blindness, or disability)", "Connecticut resident", "Must have another source of income such as Social Security, SSI, or Veterans benefits[2][6][7][8]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Cash assistance that supplements other income to meet basic needs. Includes housing allowance (maximum $400 for living alone; $200 for living with others) plus basic needs items, minus countable income. Amount determined by comparing income to monthly needs; higher income limit if living in boarding home or Residential Care Home (RCH)[7][9].",
    "varies_by": "living_arrangement|income"
  },
  "application": {
    "methods": ["Contact local Department of Social Services (DSS) office (phone numbers vary by region; statewide info at portal.ct.gov/dss)", "Apply through DSS (online via portal.ct.gov/dss, phone, mail, or in-person at local offices)", "No specific form name listed; DSS handles via standard application process[5][7]"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["DSS application for cash assistance (specific form name/number not detailed)"],
    "documents": ["Proof of income (e.g., SSI award letter, SSDI, Social Security, pay stubs)", "Proof of assets", "Proof of residency", "Proof of age, blindness, or disability (e.g., SSI determination)", "Housing costs if applicable[5][6][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered through local DSS offices, which may have regional processing differences; higher income limits for boarding homes or RCHs regardless of location[6][7]",
    "offices_or_providers": ["Local Department of Social Services (DSS) offices statewide"]
  },
  "official_source": "https://portal.ct.gov/dss",
  "gotchas": ["Must have other income to supplement—cannot be primary income source; not for those with no income[2][6]", "Homeowners face a lien on the home[6]", "Income limit is 3x SSI maximum, but benefit only if below state need standard after detailed financial review[7]", "Functional eligibility mirrors SSI (aged, blind, disabled); not automatic for low-income elderly without disability[2]", "Confused with SNAP; this is cash supplement, not food benefits[1][4]"],
  "data_shape_notes": "Supplemental cash only for those with existing income sources; varies by living arrangement (e.g., housing allowance, boarding home); asset lien on home; income test tied to SSI multiple with needs assessment"
}
